import mysql from 'mysql2/promise';
const conn = await mysql.createConnection({ host: process.env.MYSQL_HOST || 'mysql', user: process.env.MYSQL_USER || 'codeleon', password: process.env.MYSQL_PASSWORD || 'codeleon', database: process.env.MYSQL_DATABASE || 'codeleon' });
await conn.execute('CREATE TABLE IF NOT EXISTS notes (id INT AUTO_INCREMENT PRIMARY KEY, body TEXT NOT NULL)');
await conn.execute('INSERT INTO notes (body) VALUES (?)', ['hello mysql']);
const [rows] = await conn.execute('SELECT COUNT(*) AS count FROM notes');
console.log(`mysql rows: ${rows[0].count}`);
await conn.end();
